INSERT INTO questoes_simulado (simulado_id, numero, area, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, resposta_correta) VALUES ('bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb', 49, 'HUMANAS', 'Serviços em nuvem permitem armazenar arquivos e executar aplicações em servidores remotos acessíveis pela internet.

Uma vantagem da computação em nuvem é:', 'impedir o compartilhamento de arquivos', 'eliminar a necessidade de conexão com a internet', 'facilitar o acesso remoto a dados e serviços', 'reduzir a capacidade de armazenamento', 'impossibilitar cópias de segurança', 'C') ON CONFLICT (simulado_id, numero) DO NOTHING;
INSERT INTO questoes_simulado (simulado_id, numero, area, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, resposta_correta) VALUES ('bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb', 50, 'HUMANAS', 'Sensores conectados podem coletar informações em tempo real sobre temperatura, consumo de energia, localização e funcionamento de equipamentos.

Uma característica central da Internet das Coisas é:', 'isolamento completo entre dispositivos', 'conexão e troca de dados entre objetos e sistemas', 'substituição total da internet convencional', 'funcionamento exclusivamente offline', 'eliminação do uso de sensores', 'B') ON CONFLICT (simulado_id, numero) DO NOTHING;
